INSERT INTO public.page_configs (id, tenant_id, page_slug, sections, status, version, updated_by, created_at, updated_at) VALUES ('5a29c6f9-a009-4985-99c6-61367e8aa61f', '00000000-0000-0000-0000-000000000001', 'privacy', '[{"id": "privacy-header-default", "type": "page_header_basic", "order": 1, "props": {"title": "นโยบายความเป็นส่วนตัว (PDPA)", "subtitle": "", "back_href": "/register"}, "visible": true}, {"id": "privacy-content-default", "type": "rich_text", "order": 2, "props": {"title": "", "content": "<p>บริษัทให้ความสำคัญกับการคุ้มครองข้อมูลส่วนบุคคลของคุณ เราจะเก็บรวบรวม ใช้ และเปิดเผยข้อมูลส่วนบุคคล ตามวัตถุประสงค์ที่แจ้งไว้เท่านั้น</p><p>ข้อมูลที่เรารวบรวม ได้แก่ ชื่อ นามสกุล เบอร์โทรศัพท์ อีเมล วันที่เกิด และข้อมูลที่อยู่ เพื่อใช้ในการให้บริการ ส่งรางวัล และปรับปรุงประสบการณ์การใช้งาน</p><p>คุณมีสิทธิ์ในการเข้าถึง แก้ไข ลบ หรือถอนความยินยอมข้อมูลส่วนบุคคลของคุณได้ตลอดเวลา โดยติดต่อฝ่ายบริการลูกค้า</p><p style=\"opacity:0.7;font-size:12px\">อัปเดตล่าสุด: มีนาคม 2025</p>", "alignment": "left"}, "visible": true}]', 'published', 1, NULL, '2026-04-09 04:42:46.11372+00', '2026-04-09 04:42:46.11372+00');
INSERT INTO public.page_configs (id, tenant_id, page_slug, sections, status, version, updated_by, created_at, updated_at) VALUES ('9bda8a2c-a041-412e-b329-7cd3dfffbb54', '00000000-0000-0000-0000-000000000001', 'settings', '[{"id": "settings-header-default", "type": "settings_page_header", "order": 1, "props": {"title": "การตั้งค่าแอปพลิเคชัน", "subtitle": "จัดการการแจ้งเตือนและความเป็นส่วนตัว", "back_href": "/profile"}, "visible": true}, {"id": "settings-notifications-default", "type": "settings_notifications_group", "order": 2, "props": {"items": [{"label": "แต้มและภารกิจ", "locked": false, "default_on": true, "description": "แจ้งเตือนเมื่อแต้มเข้าสำเร็จ หรือภารกิจบรรลุเป้าหมาย"}, {"label": "ข่าวสารและโปรโมชัน", "locked": false, "default_on": true, "description": "รับส่วนลดพิเศษ สิทธิพิเศษ และแคมเปญใหม่ๆ ก่อนใคร"}, {"label": "ระบบและความปลอดภัย", "locked": true, "default_on": true, "description": "ห้ามปิด หากต้องการรับรู้ความเคลื่อนไหวสำคัญของบัญชี"}], "group_title": "การแจ้งเตือน (Push Notifications)"}, "visible": true}, {"id": "settings-delete-default", "type": "settings_delete_account_card", "order": 3, "props": {"cta_href": "", "group_title": "ลบบัญชีผู้ใช้", "button_label": "แจ้งขอลบบัญชีผู้ใช้", "warning_text": "หากลบบัญชี แต้มและข้อมูลทั้งหมดจะหายไปและไม่สามารถกู้คืนได้"}, "visible": true}, {"id": "settings-version-default", "type": "settings_app_version_footer", "order": 4, "props": {"text": "APP VERSION 2.0.1 (Build 491)"}, "visible": true}]', 'published', 1, NULL, '2026-04-09 04:42:46.575414+00', '2026-04-09 04:42:46.575414+00');
INSERT INTO public.page_configs (id, tenant_id, page_slug, sections, status, version, updated_by, created_at, updated_at) VALUES ('960868a7-183d-4936-b1d3-279dee5bf547', '00000000-0000-0000-0000-000000000001', 'terms', '[{"id": "terms-header-default", "type": "page_header_basic", "order": 1, "props": {"title": "ข้อกำหนดและนโยบาย", "subtitle": "นโยบายความเป็นส่วนตัวและเงื่อนไข", "back_href": "/profile"}, "visible": true}, {"id": "terms-content-default", "type": "rich_text", "order": 2, "props": {"title": "นโยบายความเป็นส่วนตัว (Privacy Policy)", "content": "<p>บริษัทให้ความสำคัญอย่างยิ่งในการคุ้มครองข้อมูลส่วนบุคคลของท่าน นโยบายความเป็นส่วนตัวนี้อธิบายถึงวิธีการที่เราเก็บรวบรวม ใช้ เปิดเผย และปกป้องข้อมูลของท่านเมื่อท่านใช้แอปพลิเคชันของเรา</p><h4>1. ข้อมูลที่เราเก็บรวบรวม</h4><ul><li>ข้อมูลที่ท่านให้ไว้โดยตรง เช่น ชื่อ นามสกุล อีเมล เบอร์โทรศัพท์</li><li>ข้อมูลการใช้งานแอปพลิเคชันและการทำรายการต่างๆ</li><li>ข้อมูลอุปกรณ์ที่ใช้เข้าถึงระบบ</li></ul><h4>2. วัตถุประสงค์การใช้ข้อมูล</h4><ul><li>เพื่อให้บริการ การสะสมแต้ม และแลกของรางวัล</li><li>เพื่อปรับปรุงและพัฒนาแอปพลิเคชันให้ดียิ่งขึ้น</li><li>เพื่อนำเสนอโปรโมชันที่ตรงใจท่าน</li></ul><h4>3. สิทธิของเจ้าของข้อมูล (PDPA)</h4><p>ท่านมีสิทธิในการขอเข้าถึง ขอแก้ไข หรือขอลบข้อมูลส่วนบุคคลของท่าน รวมถึงสิทธิในการคัดค้านการประมวลผลข้อมูลตามที่กฎหมายกำหนด</p><p style=\"text-align:center;margin-top:24px;font-size:10px;opacity:0.5\">แก้ไขล่าสุด: 1 มกราคม 2567</p>", "alignment": "left"}, "visible": true}]', 'published', 1, NULL, '2026-04-09 04:42:47.064515+00', '2026-04-09 04:42:47.064515+00');


